    {"term": "Foliar spray", "defn": "A liquid treatment applied to leaves and stems, as opposed to the root zone.", "tags": ["reference"]},
    {"term": "Drench", "defn": "A treatment applied to the growing media and root zone rather than the foliage.", "tags": ["reference"]},
    {"term": "REI (re-entry interval)", "defn": "The mandatory wait after a spray before anyone may safely re-enter the treated room; posted on the door.", "tags": ["reference"]},
    {"term": "Withholding period", "defn": "The required time after treatment before a crop may be harvested for sale, to keep residues within limits.", "tags": ["reference"]},
    {"term": "Quarantine", "defn": "Isolating incoming plants (washed on receipt, held 2+ weeks under observation) before they join the main crop.", "tags": ["reference"]},
    {"term": "Frass", "defn": "Insect droppings and debris; an early visible sign of a pest presence during scouting.", "tags": ["reference"]},
    {"term": "Sticky trap", "defn": "A coloured (usually yellow) adhesive card that catches flying pests for early warning and monitoring of pest pressure.", "tags": ["reference"]},
