    {"term": "Rockwool cube", "defn": "A spun-mineral-fiber plug that holds water and air; the medium a cutting roots into. Peat plugs serve the same role.", "tags": ["reference"]},
    {"term": "Dome", "defn": "The clear plastic humidity lid placed over a clone tray to trap moisture around rootless cuttings.", "tags": ["reference"]},
    {"term": "RH", "defn": "Relative Humidity, the percentage of moisture the air holds versus its maximum at that temperature.", "tags": ["reference"]},
    {"term": "EC", "defn": "Electrical Conductivity, a measure of nutrient strength in the feed water, in mS/cm.", "tags": ["reference"]},
    {"term": "Hardening off", "defn": "Gradually opening vents and removing the dome so rooted clones acclimate to drier room air before transplant.", "tags": ["reference"]},
