    {"term": "Topping", "defn": "Cutting off the plant's top growing tip to halt upward growth and force the branches below it to become two or more new tops, creating a wider, bushier plant.", "tags": ["reference"]},
    {"term": "FIM", "defn": "A partial topping where most but not all of the growing tip is cut, which can produce several new tops rather than the two from a clean top.", "tags": ["reference"]},
    {"term": "Apical dominance", "defn": "A plant's natural tendency to grow one central top taller than its side branches. Topping and LST break this so growth spreads evenly.", "tags": ["reference"]},
